  ('dietitian-moex-09804', 'dietitian', 'dietitian-moex-096-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關end-stage renal disease（ESRD）病患的飲食原則，下列何者敘述錯誤？', '["避免營養素缺乏、維持良好營養狀態", "低蛋白", "低鹽、限鉀、限磷", "限鈣、限維生素D"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "ce96bddf0732", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096130", "c": "113", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "096", "exam_name": "096年第二次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐、醫師分試考試", "original_question_number": 15, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09805', 'dietitian', 'dietitian-moex-096-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關Continuous ambulatory peritoneal dialysis（CAPD）病患的治療，下列敘述何者錯誤？', '["對於鈉、鉀、水的限制較寬", "具有腹膜炎和高血壓併發症", "約有600~800 kcal/天由葡萄糖來的熱量，從透析液中獲得", "蛋白質的流失高於hemodialysis（HD）患者"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "ce96bddf0732", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096130", "c": "113", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "096", "exam_name": "096年第二次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐、醫師分試考試", "original_question_number": 16, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09806', 'dietitian', 'dietitian-moex-096-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '李先生是一位腎衰竭患者，GFR＜50，年齡60歲，身高168公分，有水腫的情形，水腫前體重60公斤 ，下列有關為他設計的飲食計畫，何者錯誤？', '["目前體重在正常範圍內", "熱量：30 kcal × 60＝1800 kcal", "蛋白質：0.8 g × 60＝48 g，60% HBV", "水分攝取量：前一天液體排出量加500~700毫升，且鈉、鉀、磷量須注意"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "ce96bddf0732", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096130", "c": "113", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "096", "exam_name": "096年第二次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐、醫師分試考試", "original_question_number": 17, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09807', 'dietitian', 'dietitian-moex-096-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '慢性腎衰竭的併發症不包括下列何者？', '["骨質病變", "貧血", "水腫", "低血壓"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "ce96bddf0732", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096130", "c": "113", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "096", "exam_name": "096年第二次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐、醫師分試考試", "original_question_number": 18, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09808', 'dietitian', 'dietitian-moex-096-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '當腎絲球過濾速率（GFR）下降時，將導致血液中何種離子濃度過高？', '["磷", "鋁", "鈣", "鎂"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "ce96bddf0732", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096130", "c": "113", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "096", "exam_name": "096年第二次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐、醫師分試考試", "original_question_number": 19, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09809', 'dietitian', 'dietitian-moex-096-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '癌症病人味覺異常，對於何種味覺閥值降低？', '["苦", "甜", "酸", "鹹"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "ce96bddf0732", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096130", "c": "113", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "096", "exam_name": "096年第二次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐、醫師分試考試", "original_question_number": 20, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09810', 'dietitian', 'dietitian-moex-096-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '管灌配方不建議以單（雙）糖調整熱量，其原因為何？', '["會使滲透壓降低，導致腹瀉", "會增加病人呼吸的負荷", "會降低病人體脂肪的形成", "會降低病人的免疫力"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "ce96bddf0732", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096130", "c": "113", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "096", "exam_name": "096年第二次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐、醫師分試考試", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09811', 'dietitian', 'dietitian-moex-096-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關管灌配方飲食代謝性併發症的種類與導因，下列何者敘述錯誤？', '["高張性脫水，因高張溶液極高蛋白質配方", "高血糖症，因胰島素缺乏或單糖含量過高", "低鉀血症，因代謝性酸中毒或腎功能不足", "低鈉血症，因鈉不足或輸入過多水分"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "ce96bddf0732", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096130", "c": "113", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "096", "exam_name": "096年第二次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐、醫師分試考試", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09812', 'dietitian', 'dietitian-moex-096-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關靜脈營養溶液的組成限制，下列何者敘述錯誤？', '["蛋白質提供15~20%總熱量", "最大糖類輸入速率不得超過10 mg/kg BW/min", "最高脂質劑量不得超過2.0 g/kg BW/天", "水分的提供在1.5~3 L/天"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "ce96bddf0732", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096130", "c": "113", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "096", "exam_name": "096年第二次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐、醫師分試考試", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09813', 'dietitian', 'dietitian-moex-096-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '再餵食症候群（Refeeding syndrome）主要是由下列何種因素所造成？', '["糖類", "脂質", "蛋白質", "水分"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "ce96bddf0732", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096130", "c": "113", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "096", "exam_name": "096年第二次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐、醫師分試考試", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
